// src/views/user/MyProfile/constants/options.js
export const options = {
    salary: [
      { label: '面议', value: '0' },
      { label: '3k以下', value: '1' },
      { label: '3-5k', value: '2' },
      { label: '5-10k', value: '3' },
      { label: '10-15k', value: '4' },
      { label: '15-20k', value: '5' },
      { label: '20-30k', value: '6' },
      { label: '30-50k', value: '7' },
      { label: '50k以上', value: '8' }
    ],
    jobType: [
      { label: '全职', value: 'fulltime' },
      { label: '兼职', value: 'parttime' },
      { label: '实习', value: 'intern' },
      { label: '自由职业', value: 'freelance' }
    ],
    degree: [
      { label: '高中', value: 'highschool' },
      { label: '专科', value: 'college' },
      { label: '本科', value: 'bachelor' },
      { label: '硕士', value: 'master' },
      { label: '博士', value: 'phd' }
    ],
    proficiency: [
      { label: '入门', value: 'beginner' },
      { label: '初级', value: 'elementary' },
      { label: '中级', value: 'intermediate' },
      { label: '高级', value: 'advanced' },
      { label: '精通', value: 'proficient' }
    ],
    entryTime: [
      { label: '随时到岗', value: 'immediate' },
      { label: '一周内', value: 'oneWeek' },
      { label: '一个月内', value: 'oneMonth' },
      { label: '三个月内', value: 'threeMonths' },
      { label: '待商议', value: 'negotiate' }
    ]
  }
